CREATE TABLE public.user_purchases (
    id text NOT NULL,
    amount double precision DEFAULT 0 NOT NULL,
    book_id text NOT NULL,
    created_at timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    format text DEFAULT 'ebook'::text NOT NULL,
    payment_method text,
    status text DEFAULT 'completed'::text NOT NULL,
    updated_at timestamp(3) without time zone NOT NULL,
    user_id text NOT NULL
);


ALTER TABLE public.user_purchases OWNER TO postgres;

--
-- Name: user_roles; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.user_roles (
    id text NOT NULL,
    role public."AppRole" NOT NULL,
    user_id text NOT NULL
);


ALTER TABLE public.user_roles OWNER TO postgres;

--
-- Name: user_streaks; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.user_streaks (
    id text NOT NULL,
    best_streak integer DEFAULT 0,
    created_at timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP,
    current_streak integer DEFAULT 0,
    last_activity_date text,
    streak_updated_at timestamp(3) without time zone,
    user_id text NOT NULL
);


ALTER TABLE public.user_streaks OWNER TO postgres;

--
-- Name: user_subscriptions; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.user_subscriptions (
    id text NOT NULL,
    amount_paid double precision,
    coupon_code text,
    created_at timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    discount_amount double precision,
    end_date timestamp(3) without time zone,
    plan_id text NOT NULL,
    start_date timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    updated_at timestamp(3) without time zone NOT NULL,
    user_id text NOT NULL
);


ALTER TABLE public.user_subscriptions OWNER TO postgres;

--
-- Name: users; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.users (
    id text NOT NULL,
    email text NOT NULL,
    password_hash text NOT NULL,
    email_verified boolean DEFAULT false NOT NULL,
    created_at timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp(3) without time zone NOT NULL
);


ALTER TABLE public.users OWNER TO postgres;

--
-- Name: voices; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.voices (
    id text NOT NULL,
    created_at timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    description text,
    is_active boolean DEFAULT true NOT NULL,
    language text DEFAULT 'bn'::text NOT NULL,
    name text NOT NULL,
    provider text DEFAULT 'google'::text NOT NULL,
    updated_at timestamp(3) without time zone NOT NULL,
    voice_id text NOT NULL
);


ALTER TABLE public.voices OWNER TO postgres;

--
-- Name: withdrawal_requests; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.withdrawal_requests (
    id text NOT NULL,
    amount double precision NOT NULL,
    bank_account text,
    bank_name text,
    created_at timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    mobile_number text,
    method text DEFAULT 'bank'::text NOT NULL,
    notes text,
    processed_at timestamp(3) without time zone,
    processed_by text,
    status text DEFAULT 'pending'::text NOT NULL,
    updated_at timestamp(3) without time zone NOT NULL,
    user_id text NOT NULL
);


ALTER TABLE public.withdrawal_requests OWNER TO postgres;

